import scala.collection.mutable
import scala.collection.mutable.Queue

def nums(nums: Array[Long], edges: Array[Array[Long]]): Long = {
    val N = nums.length

    // 1. Build Adjacency Matrix
    val adj = Array.ofDim[Boolean](N) { Array.ofDim[Boolean](N) }
    for (edge <- edges) {
        // Edges are given as Longs but represent node indices (0 to N-1)
        val u = edge(0).toInt
        val v = edge(1).toInt
        adj(u)(v) = true
        adj(v)(u) = true
    }

    var count: Long = 0

    // 2. Iterate through all non-empty subsets (masks 1 to 2^N - 1)
    val totalMasks = 1 << N
    for (mask <- 1 until totalMasks) {

        // --- Check 1: Sum Parity & Calculate Subset Size ---
        var sumParity = 0
        var nodeCount = 0
        for (i <- 0 until N) {
            if ((mask & (1 << i)) != 0) {
                // nums[i] is 0 or 1, so we only care about the value modulo 2
                sumParity = (sumParity + nums(i).toInt) % 2
                nodeCount += 1
            }
        }

        // If sum is odd, skip
        if (sumParity != 0) {
            continue
        }

        // --- Check 2: Connectivity (using BFS) ---

        // Find the starting node (root)
        var root = -1
        for (i <- 0 until N) {
            if ((mask & (1 << i)) != 0) {
                root = i
                break
            }
        }

        // BFS Initialization
        val queue = Queue(root)
        val visited = Array.fill(N)(false)
        visited(root) = true
        var reachableCount = 1

        while (queue.nonEmpty) {
            val u = queue.dequeue()

            for (v <- 0 until N) {
                // Check 1: Is there an edge (u, v)?
                if (adj(u)(v)) {
                    // Check 2: Is v in the subset S (represented by mask)?
                    if ((mask & (1 << v)) != 0) {
                        // Check 3: Has v been visited?
                        if (!visited(v)) {
                            visited(v) = true
                            reachableCount += 1
                            queue.enqueue(v)
                        }
                    }
                }
            }
        }

        // If the number of reachable nodes equals the total number of nodes in S, the induced subgraph is connected.
        if (reachableCount == nodeCount) {
            count += 1
        }
    }

    count
}
