import java.util.LinkedList
import java.util.Queue

object Solution {
    def solve(nums: Array[Long]): Long = {
        val N = nums.length
        if (N == 0) return 0L

        // 1. Build Adjacency Matrix
        val adj = Array.fill(N) { Array.fill(N)(false) }
        for (edge in edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            adj(u)(v) = true
            adj(v)(u) = true
        }

        var validSubsetCount = 0L

        // 2. Iterate over all non-empty subsets (masks from 1 to 2^N - 1)
        val totalMasks = 1 << N
        for (mask <- 1 until totalMasks) {

            // 3a. Check Parity and Count Nodes (K)
            var sumParity = 0 // 0 for even, 1 for odd
            var K = 0 // Total number of nodes in the subset

            for (i <- 0 until N) {
                if ((mask & (1 << i)) != 0) {
                    K += 1
                    // nums[i] is 0 or 1. XOR operation checks parity.
                    sumParity = (sumParity + nums(i).toInt) % 2
                }
            }

            // Condition 2: Sum must be even (sumParity == 0)
            if (sumParity != 0) {
                continue
            }

            // 3b. Check Connectivity using BFS/DFS

            // Find a starting node (the lowest set bit)
            var startNode = -1
            for (i <- 0 until N) {
                if ((mask & (1 << i)) != 0) {
                    startNode = i
                    break
                }
            }

            // If K >= 1, startNode must be found.
            if (startNode == -1) continue 

            // BFS initialization
            val queue: Queue[Int] = new LinkedList[Int]()
            val visited = new Array[Boolean](N) { false }

            queue.offer(startNode)
            visited(startNode) = true
            var visitedCount = 0

            while (!queue.isEmpty()) {
                val u = queue.poll()
                visitedCount += 1

                // Check neighbors v
                for (v <- 0 until N) {
                    // 1. Is v a neighbor of u?
                    // 2. Is v part of the subset S (mask)?
                    // 3. Has v not been visited yet?
                    if (adj(u)(v) && ((mask & (1 << v)) != 0) && !visited(v)) {
                        visited(v) = true
                        queue.offer(v)
                    }
                }
            }

            // Condition 1: The induced subgraph must be connected
            if (visitedCount == K) {
                validSubsetCount += 1
            }
        }

        validSubsetCount
    }
}
