import scala.collection.mutable
import scala.math.pow

object Solver {
  /**
   * Solves the problem by iterating over all 2^N - 1 non-empty subsets,
   * checking connectivity and parity for each subset.
   *
   * @param nums Array where nums[i] is the value (0 or 1) of node i.
   * @param edges Array of edges, where edges[i] = [u, v].
   * @return The count of subsets satisfying both conditions.
   */
  def solve(nums: Array[Long], edges: Array[Array[Long]]): Long = {
    val N = nums.length
    if (N == 0) return 0

    // 1. Build Adjacency Matrix
    val adj = Array.fill(N) { Array.fill(N)(false) }
    for (edge in edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      adj(u)(v) = true
      adj(v)(u) = true
    }

    var count: Long = 0

    // 2. Iterate over all non-empty subsets (masks from 1 to 2^N - 1)
    val totalSubsets = 1L << N
    for (mask <- 1 until totalSubsets) {

      // --- Check Condition 2: Sum of values is even ---
      var sumParity = 0
      var nodesInS = 0
      for (i <- 0 until N) {
        if ((mask & (1 << i)) != 0) {
          nodesInS += 1
          // nums[i] is 0 or 1. Parity flips if nums[i] is 1.
          sumParity = sumParity xor (nums(i).toInt)
        }
      }

      if (sumParity != 0) {
        // Sum is odd, skip this subset
        continue
      }

      // --- Check Condition 1: Induced subgraph is connected ---

      // Find a starting node r (e.g., the node with the smallest index in S)
      var startNode = -1
      for (i <- 0 until N) {
        if ((mask & (1 << i)) != 0) {
          startNode = i
          break
        }
      }

      // BFS implementation
      val queue = mutable.Queue.create(startNode)
      queue.enqueue(startNode)

      // Visited mask, initialized to include the start node
      var visitedMask = (1 << startNode)
      var visitedCount = 1

      while (queue.nonEmpty) {
        val u = queue.dequeue()

        for (v <- 0 until N) {
          // Check if (u, v) is an edge AND v is in S AND v hasn't been visited
          if (adj(u)(v) && ((mask & (1 << v)) != 0) && ((visitedMask & (1 << v)) == 0)) {
            visitedMask |= (1 << v)
            visitedCount += 1
            queue.enqueue(v)
          }
        }
      }

      // If visited count equals the total number of nodes in S, it is connected
      if (visitedCount == nodesInS) {
        count += 1
      }
    }

    count
  }
}

