object Solver {
    def solve(nums: Array[Long], edges: Array[Array[Long]]): Long = {
        val N = nums.length

        // 1. Build Adjacency Matrix
        val adj = Array.ofDim[Boolean](N) { _ => Array.ofDim[Boolean](N) { _ => false } }

        for (edge in edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            adj(u)(v) = true
            adj(v)(u) = true
        }

        var count: Long = 0

        // 2. Iterate over all non-empty subsets (masks 1 to 2^N - 1)
        for (mask <- 1 until (1 << N)) {

            // --- Check Condition 2: Even Sum ---
            var sum: Int = 0
            var totalNodesInS = 0

            for (i <- 0 until N) {
                if ((mask & (1 << i)) != 0) {
                    totalNodesInS += 1
                    // Since nums[i] is 0 or 1, we can safely cast to Int
                    sum += nums(i).toInt 
                }
            }

            if (sum % 2 != 0) {
                continue // Fails Condition 2
            }

            // --- Check Condition 1: Connectivity ---

            // Find a starting node r (lowest indexed node in S)
            var r = -1
            for (i <- 0 until N) {
                if ((mask & (1 << i)) != 0) {
                    r = i
                    break
                }
            }

            // BFS initialization
            val queue = mutable.Queue.newBuilder[Int]()
            val visited = new Array[Boolean](N) { _ => false }

            queue.enqueue(r)
            visited(r) = true
            var visitedCount = 1

            while (queue.nonEmpty) {
                val u = queue.dequeue()

                for (v <- 0 until N) {
                    // 1. Is there an edge (u, v)?
