                                visitedCount += 1
                                queue.enqueue(v)
                            }
                        }
                    }
                }
            }

            // Connectivity check: Did BFS visit all nodes in S?
            if (visitedCount == totalNodesInS) {
                count += 1
            }
        }

        count
    }
}

